// Moneda por defecto del ecosistema Dotrino: rasterización de moneda.svg (root del
// paquete) a PNG 256x256 con transparencia, embebida como data URI. Sin assets
// externos en runtime. 256px = nítida del trigger de 38px hasta el preview de 240px.
// La app consumidora puede sobreescribir con el atributo `coin`.
// Para regenerar: inkscape moneda.svg --export-type=png -w 256 -h 256 -> base64.

export const COIN_DATA_URI = "data:image/png;base64,"
